	int earn=0;

	for(int i=k;i>=1;i--)

	{

		for(int v:ve[i]) q.push(v);

		if(!q.empty())

		{

			earn+=q.top();

			q.pop();

		}

	}

	cout<<earn;





	return 0;

 }

